const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

// PostgreSQL connection pool configuration
const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database_name',
  password: 'your_password',
  port: 5432,
});

// Create a new record in the table
app.post('/table', async (req, res) => {
  try {
    const { name, value } = req.body;
    const result = await pool.query('INSERT INTO your_table_name (name, value) VALUES ($1, $2) RETURNING *', [name, value]);
    res.status(201).json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: 'An error occurred while creating the record.' });
  }
});

// Read all records from the table
app.get('/table', async (req, res) => {
  try {
    const result = await pool.query('SELECT * FROM your_table_name');
    res.json(result.rows);
  } catch (error) {
    res.status(500).json({ error: 'An error occurred while fetching the records.' });
  }
});

// Update a record in the table
app.put('/table/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const { name, value } = req.body;
    const result = await pool.query('UPDATE your_table_name SET name = $1, value = $2 WHERE id = $3 RETURNING *', [name, value, id]);
    res.json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: 'An error occurred while updating the record.' });
  }
});

// Delete a record from the table
app.delete('/table/:id', async (req, res) => {
  try {
    const { id } = req.params;
    await pool.query('DELETE FROM your_table_name WHERE id = $1', [id]);
    res.status(204).send();
  } catch (error) {
    res.status(500).json({ error: 'An error occurred while deleting the record.' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});